plugin.executeCode:
const lines = input.split('\n').filter(l => /^\|/.test(l.trim()));
const rows = [];
for (const line of lines) {
  // Skip separator rows
  if (/^\|[-| :]+\|\s*$/.test(line.trim())) continue;
  const cells = line.trim().replace(/^\|/, '').replace(/\|$/, '').split('|').map(c => {
    const v = c.trim();
    // Quote cells that contain commas, newlines, or double-quotes
    if (v.includes(',') || v.includes('"') || v.includes('\n')) {
      return '"' + v.replace(/"/g, '""') + '"';
    }
    return v;
  });
  rows.push(cells.join(','));
}
if (rows.length === 0) return { output: '', error: 'No Markdown table found.' };
return { output: rows.join('\n'), outputLanguage: 'csv' };
